  project: "batch-app",
  dirs: ["./trigger"],
});

import { client, batch } from "@trigger.dev/sdk";

// Initialize the client
client.define({
  id: "batch-app",
  name: "Batch Processing App",
});

// Sub-task that processes a single item
// This task accepts an id and returns it
client.defineJob({
  id: "process-item",
  name: "Process Item",
  version: "1.0.0",
  run: async (payload, { ctx, logger }) => {
    const { id } = payload;

    logger.info(`Processing item with ID: ${id}`);

    // Simply return the id as required
    return {
      id,
      processed: true,
      timestamp: new Date().toISOString(),
    };
  },
});

// Parent task that processes multiple items in parallel
// This task takes an array of IDs and uses batch.triggerByTaskAndWait
client.defineJob({
  id: "batch-processor",
  name: "Batch Processor",
  version: "1.0.0",
  run: async (payload, { ctx, logger }) => {
    const { ids } = payload;

    logger.info(`Starting batch processing for ${ids.length} items`);

    // Use batch.triggerByTaskAndWait to process all IDs in parallel
    // This is the Trigger.dev V4 way to run sub-tasks in parallel
    const results = await batch.triggerByTaskAndWait(
      ids.map((id) => ({
        task: "process-item",
        payload: { id },
      }))
    );

    logger.info(`Batch processing completed. Processed ${results.length} items`);

    // Return the array of results
    return {
      results,
      totalProcessed: results.length,
      timestamp: new Date().toISOString(),
    };
  },
});

